<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Conway's Game of Life</title>
<style>
  body {
    background-color: #121212;
    color: #e0e0e0;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: 100vh;
    margin: 0;
    padding: 20px;
    box-sizing: border-box;
  }

  h1 {
    font-weight: 300;
    letter-spacing: 2px;
    margin-bottom: 20px;
    text-transform: uppercase;
    color: #4CAF50;
    text-shadow: 0 2px 4px rgba(0,0,0,0.5);
  }

  #life-container {
    position: relative;
    box-shadow: 0 10px 30px rgba(0, 0, 0, 0.6);
    border-radius: 8px;
    overflow: hidden;
    background-color: #1e1e1e;
    padding: 4px;
    margin-bottom: 20px;
  }

  canvas {
    display: block;
    cursor: crosshair;
    /* Ensure at least 400x400 CSS pixels */
    width: 500px;
    height: 500px;
    background-color: #2c2c2c;
    border-radius: 4px;
  }

  .controls {
    display: flex;
    gap: 10px;
    margin-top: 10px;
    flex-wrap: wrap;
    justify-content: center;
  }

  button {
    padding: 12px 24px;
    border: none;
    border-radius: 6px;
    font-size: 14px;
    font-weight: bold;
    cursor: pointer;
    transition: all 0.2s cubic-bezier(0.4, 0, 0.2, 1);
    text-transform: uppercase;
    letter-spacing: 1px;
    min-width: 90px;
    color: white;
    box-shadow: 0 2px 5px rgba(0,0,0,0.3);
  }

  button:hover {
    transform: translateY(-2px);
    box-shadow: 0 4px 10px rgba(0,0,0,0.4);
  }

  button:active {
    transform: translateY(0);
    box-shadow: 0 1px 2px rgba(0,0,0,0.3);
  }

  #step { background-color: #2196F3; }
  #play { background-color: #4CAF50; }
  #random { background-color: #FF9800; }
  #clear { background-color: #f44336; }

  .status {
    margin-top: 15px;
    font-size: 12px;
    color: #888;
    height: 16px;
  }
</style>
</head>
<body>

<h1>Game of Life</h1>

<div id="life-container">
  <canvas id="life" width="500" height="500"></canvas>
</div>

<div class="controls">
  <button id="step">Step</button>
  <button id="play">Play</button>
  <button id="random">Random</button>
  <button id="clear">Clear</button>
</div>

<div class="status" id="status">Ready</div>

<script>
(function() {
  // Configuration: Grid dimensions >= 40x40
  const W = 50; 
  const H = 50; 
  const CELL_SIZE = 10; 

  // DOM Elements
  const canvas = document.getElementById('life');
  const ctx = canvas.getContext('2d');
  const statusEl = document.getElementById('status');

  // State Buffers (Double Buffering for Simultaneous Update)
  let grid = createGrid(W, H);
  let nextGrid = createGrid(W, H);

  function createGrid(w, h) {
    return Array.from({ length: h }, () => Array(w).fill(0));
  }

  // API Implementation exposed on window
  window.life = {
    w: W,
    h: H,
    get(x, y) {
      if (x < 0 || x >= W || y < 0 || y >= H) return 0;
      return grid[y][x];
    },
    set(x, y, v) {
      if (x >= 0 && x < W && y >= 0 && y < H) {
        grid[y][x] = v ? 1 : 0;
      }
    },
    step: function() {
      computeNext();
      draw();
    },
    clear: function() {
      grid = createGrid(W, H);
      nextGrid = createGrid(W, H);
      draw();
      updateStatus('Cleared');
    }
  };

  // Simulation Logic (B3/S23)
  function computeNext() {
    for (let y = 0; y < H; y++) {
      for (let x = 0; x < W; x++) {
        const neighbors = countNeighbors(x, y);
        const current = grid[y][x];

        if (current === 1) {
          // Live cell: survives with 2 or 3 neighbors
          nextGrid[y][x] = (neighbors === 2 || neighbors === 3) ? 1 : 0;
        } else {
          // Dead cell: becomes alive with exactly 3 neighbors
          nextGrid[y][x] = (neighbors === 3) ? 1 : 0;
        }
      }
    }

    // Swap buffers
    let temp = grid;
    grid = nextGrid;
    nextGrid = temp;
  }

  function countNeighbors(x, y) {
    let count = 0;
    for (let dy = -1; dy <= 1; dy++) {
      for (let dx = -1; dx <= 1; dx++) {
        if (dx === 0 && dy === 0) continue;
        const nx = x + dx;
        const ny = y + dy;
        // Edges are dead: check bounds strictly
        if (nx >= 0 && nx < W && ny >= 0 && ny < H) {
          count += grid[ny][nx];
        }
      }
    }
    return count;
  }

  // Rendering
  function draw() {
    ctx.fillStyle = '#2c2c2c';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    ctx.fillStyle = '#4CAF50'; // Live cell color

    for (let y = 0; y < H; y++) {
      for (let x = 0; x < W; x++) {
        if (grid[y][x] === 1) {
          // Draw slightly smaller than cell size for grid effect
          ctx.fillRect(x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE - 1, CELL_SIZE - 1);
        }
      }
    }
  }

  // Controls Logic
  let isRunning = false;
  let intervalId = null;

  document.getElementById('step').addEventListener('click', () => {
    if (isRunning) return; 
    computeNext();
    draw();
    updateStatus('Stepped');
  });

  const playBtn = document.getElementById('play');
  playBtn.addEventListener('click', togglePlay);

  function togglePlay() {
    if (isRunning) {
      clearInterval(intervalId);
      isRunning = false;
      playBtn.textContent = 'Play';
      playBtn.style.backgroundColor = '#4CAF50';
      updateStatus('Paused');
    } else {
      intervalId = setInterval(() => {
        computeNext();
        draw();
      }, 100); 
      isRunning = true;
      playBtn.textContent = 'Pause';
      playBtn.style.backgroundColor = '#FF9800';
      updateStatus('Running');
    }
  }

  document.getElementById('random').addEventListener('click', () => {
    for (let y = 0; y < H; y++) {
      for (let x = 0; x < W; x++) {
        grid[y][x] = Math.random() > 0.7 ? 1 : 0; 
      }
    }
    draw();
    updateStatus('Randomized');
  });

  document.getElementById('clear').addEventListener('click', () => {
    window.life.clear();
  });

  function updateStatus(msg) {
    statusEl.textContent = msg;
    setTimeout(() => { if(statusEl.textContent === msg) statusEl.textContent = 'Ready'; }, 2000);
  }

  // Interaction (Painting)
  let isDrawing = false;

  function getGridPos(e) {
    const rect = canvas.getBoundingClientRect();
    const x = Math.floor((e.clientX - rect.left) / CELL_SIZE);
    const y = Math.floor((e.clientY - rect.top) / CELL_SIZE);
    return { x, y };
  }

  function paintCell(x, y) {
    if (x >= 0 && x < W && y >= 0 && y < H) {
      grid[y][x] = grid[y][x] ? 0 : 1; // Toggle
      draw();
    }
  }

  canvas.addEventListener('mousedown', (e) => {
    isDrawing = true;
    const pos = getGridPos(e);
    paintCell(pos.x, pos.y);
  });

  window.addEventListener('mouseup', () => {
    isDrawing = false;
  });

  canvas.addEventListener('mousemove', (e) => {
    if (!isDrawing) return;
    const pos = getGridPos(e);
    if (pos.x >= 0 && pos.x < W && pos.y >= 0 && pos.y < H) {
      grid[pos.y][pos.x] = grid[pos.y][pos.x] ? 0 : 1;
      draw();
    }
  });

  // Initial Draw
  draw();

})();
</script>
</body>
</html>
